var body = $json.body || $json;
var findings = body.findings || [];
var requirements = body.requirements || {};
var procurementInfo = body.procurementInfo || {};

// Filter only non-compliant findings for legal review
var nonCompliant = findings.filter(function(f) {
  return f.status !== 'COMPLIANT';
});

var procStr = JSON.stringify(procurementInfo, null, 2).substring(0, 3000);
var reqStr = JSON.stringify(requirements, null, 2).substring(0, 20000);
var findingsStr = JSON.stringify(nonCompliant, null, 2).substring(0, 40000);

var p = 'Ти си юрист-експерт по обществени поръчки. Задачата ти е да преобразуваш техническите констатации във ФОРМАЛНИ ПРАВНИ МОТИВИ ЗА ОТСТРАНЯВАНЕ по модела на реални протоколи на оценителни комисии.\n\n';
p += '## ДАННИ ЗА ПОРЪЧКАТА:\n' + procStr + '\n\n';
p += '## ИЗИСКВАНИЯ ОТ ДОКУМЕНТАЦИЯТА:\n' + reqStr + '\n\n';
p += '## КОНСТАТАЦИИ ЗА НЕСЪОТВЕТСТВИЯ (' + nonCompliant.length + ' бр.):\n' + findingsStr + '\n\n';
p += '## ЗАДАЧА\n';
p += 'Трансформирай всяка констатация в ФОРМАЛЕН ПРАВЕН МОТИВ, следвайки структурата на реален протокол за отстраняване от процедура по ЗОП.\n\n';
p += '## СТРУКТУРА НА ПРАВЕН МОТИВ (ЗА ВСЯКА КОНСТАТАЦИЯ):\n\n';
p += '### 1. Изискване на възложителя\n';
p += '"Съгласно [точна секция] от документацията за участие, участниците са длъжни да представят [дословен текст на изискването]."\n\n';
p += '### 2. Констатирано несъответствие\n';
p += '"При проверка на техническото предложение на участника е констатирано следното: [описание на конкретното несъответствие с ДОСЛОВНИ ЦИТАТИ и конкретни числа/позиции]"\n\n';
p += '### 3. Правен извод\n';
p += '"Посочените обстоятелства обосновават извод за несъответствие на техническото предложение с изискванията на [секция] от документацията, което представлява основание за отстраняване по чл. 107, т. 2, буква \'а\' от ЗОП — офертата на участника не отговаря на предварително обявените условия на поръчката."\n\n';
p += 'ИЛИ при по-леки несъответствия:\n';
p += '"Констатираните непълноти не представляват самостоятелно основание за отстраняване, но обосновават по-ниска оценка по показател [X] от методиката за оценка."\n\n';
p += '## КАТЕГОРИЗАЦИЯ НА ВСЕКИ МОТИВ:\n';
p += '- **DISQUALIFY**: Ясно и безспорно нарушение на ЗАДЪЛЖИТЕЛНО изискване. Техническото предложение не отговаря на условията — основание по чл. 107, т. 2, буква \'а\' ЗОП.\n';
p += '- **REDUCE_POINTS**: Непълноти, които не са основание за отстраняване, но водят до по-ниска оценка по съответния показател.\n';
p += '- **REQUEST_CLARIFICATION**: Неясноти, които могат да бъдат изяснени по чл. 104, ал. 5 ЗОП.\n';
p += '- **NO_VIOLATION**: Констатацията не се потвърждава при правен анализ.\n\n';
p += '## ГРУПИРАНЕ НА МОТИВИТЕ\n';
p += 'В края ГРУПИРАЙ всички мотиви в ОБОБЩЕН ИЗВОД:\n';
p += '"На основание гореизложеното, комисията констатира следните несъответствия на техническото предложение: [N] нарушения на задължителни изисквания, [M] непълноти, водещи до намалена оценка. Посочените обстоятелства в тяхната съвкупност обосновават извод за [отстраняване/допускане с бележки] на участника."\n\n';
p += '## КРИТИЧНИ ПРАВИЛА:\n';
p += '- Използвай ТОЧНИ правни норми — чл. 107, т. 2, буква \'а\' от ЗОП (не т. 1, не ал. 1)\n';
p += '- чл. 107, т. 2, буква \'а\' = "офертата на участника не отговаря на предварително обявените условия на поръчката"\n';
p += '- Всяко твърдение подкрепяй с КОНКРЕТНИ факти от констатациите\n';
p += '- НЕ добавяй мотиви извън предоставените констатации\n';
p += '- Бъди КОНСЕРВАТИВЕН — отстраняване САМО при ясни и безспорни нарушения на задължителни изисквания\n';
p += '- Отчитай принципа на СЪРАЗМЕРНОСТ — дребни дефекти ≠ отстраняване\n';
p += '- Разграничавай ФОРМАЛНА НЕРЕДОВНОСТ (може да се отстрани) от СЪЩЕСТВЕНО НЕСЪОТВЕТСТВИЕ (основание за отстраняване)\n\n';
p += '## ФОРМАТ\n';
p += 'Върни САМО валиден JSON:\n';
p += '{\n';
p += '  "legal_motives": [\n';
p += '    {\n';
p += '      "requirement_id": "R1",\n';
p += '      "motive_text": "ПЪЛЕН ТЕКСТ на правния мотив — готов за вписване в протокол (3-5 изречения)",\n';
p += '      "legal_basis": "чл. 107, т. 2, буква \'а\' от ЗОП",\n';
p += '      "recommendation": "DISQUALIFY|REDUCE_POINTS|REQUEST_CLARIFICATION|NO_VIOLATION",\n';
p += '      "confidence": "HIGH|MEDIUM|LOW",\n';
p += '      "severity": "CRITICAL|MAJOR|MINOR",\n';
p += '      "kzk_risk_assessment": "Кратка оценка на риска при обжалване пред КЗК"\n';
p += '    }\n';
p += '  ],\n';
p += '  "overall_conclusion": {\n';
p += '    "action": "DISQUALIFY|ACCEPT_WITH_REMARKS|ACCEPT",\n';
p += '    "disqualification_grounds_count": 0,\n';
p += '    "summary_motive": "ОБОБЩЕН ПРАВЕН ИЗВОД — готов за вписване в протокол (2-3 изречения)",\n';
p += '    "legal_basis": "чл. 107, т. 2, буква \'а\' от ЗОП"\n';
p += '  },\n';
p += '  "procedural_notes": ["Процедурни бележки за комисията"]\n';
p += '}';

return [{ json: { prompt: p, nonCompliantCount: nonCompliant.length } }];

var raw = ($json.text || $json.response || '').trim();

// Handle error from chainLlm
if ($json.error || $json.errorMessage || (!raw && $input.first().json.error)) {
  return [{ json: {
    legalValidation: {
      legal_motives: [],
      overall_conclusion: {
        action: 'ACCEPT_WITH_REMARKS',
        disqualification_grounds_count: 0,
        summary_motive: 'Legal validation AI error — manual review required'
      },
      procedural_notes: ['AI legal validator encountered an error. All findings require manual legal review.']
    }
  } }];
}

var result;
try {
  result = JSON.parse(raw);
} catch (e) {
  var m = raw.match(/```(?:json)?\s*([\s\S]*?)```/);
  var candidate = m ? m[1].trim() : raw;
  try {
    var s = candidate.indexOf('{');
    var e2 = candidate.lastIndexOf('}');
    var js = candidate.substring(s, e2 + 1).replace(/,\s*([\]\}])/g, '$1');
    result = JSON.parse(js);
  } catch (e3) {
    result = {
      legal_motives: [],
      overall_conclusion: {
        action: 'ACCEPT_WITH_REMARKS',
        disqualification_grounds_count: 0,
        summary_motive: 'Parse error — manual review required'
      },
      procedural_notes: ['JSON parse failed. Raw AI response needs manual review.']
    };
  }
}

return [{ json: { legalValidation: result } }];
